ilroad...",    "🔍 Reading reporting marks...",    "📦 Determining equipment type...",    "📏 Estimating dimensions...",    "🎨 Identifying paint scheme...",    "📚 Comparing prototype data...",    "🧠 Building equipment profile...",    "✅ Finalizing results..."];document    .getElementById('aiScanForm')    .addEventListener('submit', function(e) {        e.preventDefault();        document            .getElementById('loadingOverlay')            .style.display = 'block';        const button =            document.getElementById('analyzeButton');        button.disabled = true;        button.innerText = 'Analyzing...';        let index = 0;        const interval = setInterval(function() {            index++;            if (index >= aiMessages.length) {                index = aiMessages.length - 1;            }            document.getElementById('loadingMessage')                .innerText = aiMessages[index];        }, 1000);        setTimeout(() => {            clearInterval(interval);            document                .getElementById('aiScanForm')                .submit();        }, 9000);    });</script><script>document    .getElementById('photo')    .addEventListener('change', function(e) {        const file = e.target.files[0];        if (!file) {            return;        }        const preview =            document.getElementById('preview');        preview.src =            URL.createObjectURL(file);        preview.style.display = 'block';    });</script><?php include '../includes/footer.php'; ?>